#include <iostream>\n#include <vector>\n\nclass Graph {\n public:\n  explicit Graph(int n) : n_(n + 1) {\n    p_.resize(n_);\n    for (int i = 0; i < n_; i++) {\n      p_[i] = i;\n    }\n    r_.resize(n_, 0);\n    s_.resize(n_, 0);\n  }\n\n  void AddEdge(int a, int b, int w) {\n    a = Get(a);\n    b = Get(b);\n    if (a != b) {\n      Union(a, b);\n    }\n    s_[Get(b)] += w;\n  }\n\n  int GetWeight(int a) {\n    return s_[Get(a)];\n  }\n\n private:\n  int Get(int a) {\n    if (p_[a] != a) {\n      p_[a] = Get(p_[a]);\n    }\n    return p_[a];\n  }\n\n  void Union(int a, int b) {\n    a = Get(a);\n    b = Get(b);\n    if (r_[a] > r_[b]) {\n      std::swap(a, b);\n    }\n    if (r_[a] == r_[b]) {\n      r_[b]++;\n    }\n    s_[b] += s_[a];\n    p_[a] = b;\n  }\n\n  int n_;\n  std::vector<int> s_;\n  std::vector<int> p_;\n  std::vector<int> r_;\n};\n\nint main() {\n  // magic words\n  std::cin.tie(nullptr);\n  std::cout.tie(nullptr);\n  std::ios_base::sync_with_stdio(false);\n\n  int n = 0;\n  int m = 0;\n  std::cin >> n >> m;\n\n  Graph g(n);\n  for (int i = 0; i < m; i++) {\n    int command = 1;\n    int a = 0;\n    int b = 0;\n    int w = 0;\n    std::cin >> command >> a;\n    if (command == 1) {\n      std::cin >> b >> w;\n      g.AddEdge(a, b, w);\n    } else {\n      std::cout << g.GetWeight(a) << '\\n';\n    }\n  }\n  return 0;\n}